(window.webpackJsonp=window.webpackJsonp||[]).push([[80],{707:function(n,r){n.exports="\x3c!-- \r\ntitle: 22-Centos部署Nginx\r\nsort: \r\n--\x3e \r\n# CentOS安装Nginx\r\n\r\n- Nginx 是一个高性能的HTTP和反向代理web服务器。\r\n\r\n## 安装\r\n\r\n- yum安装：\r\n\r\n  ```bash\r\n  sudo yum -y install nginx\t\t# 安装nginx\r\n  sudo yum remove nginx\t\t\t# 卸载nginx\r\n  ```\r\n\r\n- 配置nginx服务：\r\n\r\n  ```bash\r\n  sudo systemctl enable nginx \t# 设置开机启动 \r\n  sudo service nginx start \t\t# 启动 nginx 服务\r\n  sudo service nginx stop \t\t# 停止 nginx 服务\r\n  sudo service nginx restart \t\t# 重启 nginx 服务\r\n  sudo service nginx reload \t\t# 重新加载配置\r\n  ```\r\n\r\n- 查看是否设置成功：\r\n\r\n  ```bash\r\n  ps -ef | grep nginx\r\n  ```\r\n\r\n## 配置文件\r\n\r\n- nginx.conf说明：\r\n\r\n```bash\r\n# user  nobody;\r\nworker_processes  1; # 工作进程：数目。根据硬件调整，通常等于cpu数量或者2倍cpu数量。\r\n \r\n# 错误日志存放路径\r\n# error_log  logs/error.log;\r\n# error_log  logs/error.log  notice;\r\n# error_log  logs/error.log  info;\r\n \r\n# pid        logs/nginx.pid; \t# nginx进程pid存放路径\r\n \r\n \r\nevents {\r\n    worker_connections  1024; \t# 工作进程的最大连接数量\r\n}\r\n \r\n \r\nhttp {\r\n    include       mime.types; \t# 指定mime类型，由mime.type来定义\r\n    default_type  application/octet-stream;\r\n \r\n    # 日志格式设置\r\n    # log_format  main  '$remote_addr - $remote_user [$time_local] \"$request\" '\r\n    #                  '$status $body_bytes_sent \"$http_referer\" '\r\n    #                  '\"$http_user_agent\" \"$http_x_forwarded_for\"';\r\n \r\n    #access_log  logs/access.log  main; #用log_format指令设置日志格式后，需要用access_log来指定日志文件存放路径\r\n\t\t\t\t\t\r\n    sendfile        on; # 指定nginx是否调用sendfile函数来输出文件，对于普通应用，必须设置on。\r\n\t\t\t如果用来进行下载等应用磁盘io重负载应用，可设着off，以平衡磁盘与网络io处理速度，降低系统uptime。\r\n    # tcp_nopush     on; # 此选项允许或禁止使用socket的TCP_CORK的选项，此选项仅在sendfile的时候使用\r\n \r\n    # keepalive_timeout  0;  # keepalive超时时间\r\n    keepalive_timeout  65;\r\n \r\n    #gzip  on; # 开启gzip压缩服务\r\n \r\n    # 虚拟主机\r\n    server {\r\n        listen       80;  # 配置监听端口号\r\n        server_name  localhost; # 配置访问域名，域名可以有多个，用空格隔开\r\n \r\n        #charset koi8-r; # 字符集设置\r\n \r\n        #access_log  logs/host.access.log  main;\r\n \r\n        location / {\r\n            root   html;\r\n            index  index.html index.htm;\r\n        }\r\n        # 错误跳转页\r\n        # error_page  404              /404.html; \r\n \r\n        # redirect server error pages to the static page /50x.html\r\n        #\r\n        error_page   500 502 503 504  /50x.html;\r\n        location = /50x.html {\r\n            root   html;\r\n        }\r\n \r\n        # proxy the PHP scripts to Apache listening on 127.0.0.1:80\r\n        #\r\n        # location ~ \\.php$ {\r\n        #    proxy_pass   http://127.0.0.1;\r\n        #}\r\n \r\n        # pass the PHP scripts to FastCGI server listening on 127.0.0.1:9000\r\n        #\r\n        # location ~ \\.php$ { #请求的url过滤，正则匹配，~为区分大小写，~*为不区分大小写。\r\n        #    root           html; #根目录\r\n        #    fastcgi_pass   127.0.0.1:9000; #请求转向定义的服务器列表\r\n        #    fastcgi_index  index.php; # 如果请求的Fastcgi_index URI是以 / 结束的, 该指令设置的文件会被附加到URI的后面并保存在变量$fastcig_script_name中\r\n        #    fastcgi_param  SCRIPT_FILENAME  /scripts$fastcgi_script_name;\r\n        #    include        fastcgi_params;\r\n        #}\r\n \r\n        # deny access to .htaccess files, if Apache's document root\r\n        # concurs with nginx's one\r\n        #\r\n        #location ~ /\\.ht {\r\n        #    deny  all;\r\n        #}\r\n    }\r\n \r\n \r\n    # another virtual host using mix of IP-, name-, and port-based configuration\r\n    #\r\n    #server {\r\n    #    listen       8000;\r\n    #    listen       somename:8080;\r\n    #    server_name  somename  alias  another.alias;\r\n \r\n    #    location / {\r\n    #        root   html;\r\n    #        index  index.html index.htm;\r\n    #    }\r\n    #}\r\n \r\n \r\n    # HTTPS server\r\n    #\r\n    #server {\r\n    #    listen       443 ssl;  #监听端口\r\n    #    server_name  localhost; #域名\r\n \r\n    #    ssl_certificate      cert.pem; #证书位置\r\n    #    ssl_certificate_key  cert.key; #私钥位置\r\n \r\n    #    ssl_session_cache    shared:SSL:1m;\r\n    #    ssl_session_timeout  5m; \r\n \r\n    #    ssl_ciphers  HIGH:!aNULL:!MD5; #密码加密方式\r\n    #    ssl_prefer_server_ciphers  on; # ssl_prefer_server_ciphers  on; #\r\n \r\n \r\n    #    location / {\r\n    #        root   html;\r\n    #        index  index.html index.htm;\r\n    #    }\r\n    #}\r\n \r\n}\r\n```"}}]);